var NumArray = function(nums) {
    this.prefix = [0];
    for (const v of nums) {
        this.prefix.push(this.prefix[this.prefix.length - 1] + v);
    }
};
NumArray.prototype.sumRange = function(left, right) {
    return this.prefix[right + 1] - this.prefix[left];
};
